class Solution:
    def minimumOperations(self, nums):
        n = len(nums)
        seen = set()
        start = n
        for i in range(n - 1, -1, -1):
            if nums[i] in seen:
                break
            seen.add(nums[i])
            start = i
        return (start + 2) // 3

