var minimumOperations = function(nums) {
    const n = nums.length;
    const seen = new Set();
    let start = n;
    for (let i = n - 1; i >= 0; i--) {
        if (seen.has(nums[i])) break;
        seen.add(nums[i]);
        start = i;
    }
    return Math.floor((start + 2) / 3);
};
